def solution(n: int = 1000):
    count = 0
    num, den = 3, 2
    for _ in range(1000):
        if len(str(num)) > len(str(den)):
            count += 1
        # Correct recurrence: next_num = num + 2*den, next_den = num + den
        num, den = num + 2 * den, num + den
    return count


if __name__ == "__main__":
    print(solution(1000))
